    .then(res => {
      if (!res.ok) throw new Error('User not found');
      return res.json();
    })
    .then(user => displayProfile(user))
    .catch(err => alert(err.message));

  // 2. Fetch user repos (parallel!)
  fetch(`https://api.github.com/users/${username}/repos`)
    .then(res => res.json())
